// ══════════════════════════════════════════
// 工具函式
// ══════════════════════════════════════════
function getSubmitWeek(ts) {
  const t = new Date(ts);
  for (const w of WEEKS) {
    if (t >= new Date(w.start+"T00:00:00") && t <= new Date(w.end+"T23:00:00")) return w.week;
  }
  return WEEKS.length;
}
function getCurrentWeek() {
  const now = new Date();
  for (const w of WEEKS) {
    if (now >= new Date(w.start+"T00:00:00") && now <= new Date(w.end+"T23:00:00")) return w.week;
  }
  if (now < new Date(WEEKS[0].start+"T00:00:00")) return 1;
  return WEEKS.length;
}

function getChar(id) { return CHARACTERS.find(c=>c.id===id) || CHARACTERS[0]; }

// ══════════════════════════════════════════
// 角色頭像元件（使用官方圖片）
// ══════════════════════════════════════════
function CharAvatar({ charId, size=60 }) {
  const c = getChar(charId);
  if (c.img) {
    return (
      <img src={c.img} alt={c.nameZh||c.name}
        style={{width:size,height:size,objectFit:"cover",borderRadius:"50%",
          border:`2px solid ${c.color}`,background:c.bg,flexShrink:0,display:"block"}} />
    );
  }
  return (
    <div style={{width:size,height:size,borderRadius:"50%",background:c.bg,
      border:`2px solid ${c.color}`,display:"flex",alignItems:"center",
      justifyContent:"center",fontSize:size*0.3,fontWeight:900,color:c.color,flexShrink:0}}>
      {(c.nameZh||c.name).slice(0,2)}
    </div>
  );
}

// ══════════════════════════════════════════
// 音效
// ══════════════════════════════════════════
function useSfx() {
  const ctx = useRef(null);
  const ac = () => { if (!ctx.current) ctx.current = new (window.AudioContext||window.webkitAudioContext)(); return ctx.current; };
  const t = (f,d,tp="square",v=0.22) => {
    try {
      const a=ac(),o=a.createOscillator(),g=a.createGain();
      o.connect(g);g.connect(a.destination);
      o.type=tp;o.frequency.value=f;
      g.gain.setValueAtTime(v,a.currentTime);
      g.gain.exponentialRampToValueAtTime(0.001,a.currentTime+d);
      o.start();o.stop(a.currentTime+d);
    } catch {}
  };
  return {
    coin:    ()=>{t(988,.1);setTimeout(()=>t(1319,.18),100);},
    star:    ()=>{[523,659,784,1047].forEach((f,i)=>setTimeout(()=>t(f,.13),i*80));},
    levelUp: ()=>{[523,659,784,1047,1319].forEach((f,i)=>setTimeout(()=>t(f,.18,"sawtooth",.18),i*100));},
    powerUp: ()=>{[392,523,659,784].forEach((f,i)=>setTimeout(()=>t(f,.15,"triangle",.28),i*90));},
    error:   ()=>{t(200,.15);setTimeout(()=>t(150,.25),120);},
    login:   ()=>{[440,550,660].forEach((f,i)=>setTimeout(()=>t(f,.12),i*110));},
    select:  ()=>{t(660,.07);setTimeout(()=>t(880,.1),80);},
    setup:   ()=>{[523,659,784,1047,1319].forEach((f,i)=>setTimeout(()=>t(f,.15,"triangle",.2),i*90));},
    taskSfx: (tid)=>{
      const m={friend:"coin",shopping:"coin",survey:"powerUp",bond:"powerUp",expo:"star",close:"levelUp"};
      const fn={coin:()=>{t(988,.1);setTimeout(()=>t(1319,.18),100);},star:()=>{[523,659,784,1047].forEach((f,i)=>setTimeout(()=>t(f,.13),i*80));},levelUp:()=>{[523,659,784,1047,1319].forEach((f,i)=>setTimeout(()=>t(f,.18,"sawtooth",.18),i*100));},powerUp:()=>{[392,523,659,784].forEach((f,i)=>setTimeout(()=>t(f,.15,"triangle",.28),i*90));}};
      fn[m[tid]||"coin"]?.();
    },
  };
}

// ══════════════════════════════════════════
// 主 App
// ══════════════════════════════════════════
export default function App() {
  const [screen, setScreen]       = useState("press");
  const [users, setUsers]         = useState(SEED_MEMBERS);
  const [subs, setSubs]           = useState([]);
  const [weekBonuses, setWeekBonuses] = useState({});
  const [me, setMe]               = useState(null);
  const [tab, setTab]             = useState("board");
  const [toast, setToast]         = useState(null);
  const [loaded, setLoaded]       = useState(false);
  const sfx = useSfx();

  useEffect(()=>{
    // 即時監聽 Firestore — 任何裝置寫入都會自動同步
    let initialised = false;
    // 安全逾時：若 Firestore 8秒內未回應，強制顯示頁面
    const safetyTimer = setTimeout(() => {
      if (!initialised) { initialised = true; setLoaded(true); }
    }, 8000);

    const unsubUsers = onSnapshot(USERS_DOC, snap => {
      if (snap.exists()) {
        const data = snap.data().data;
        if (Array.isArray(data)) setUsers(data);
      }
      if (!initialised) { initialised = true; setLoaded(true); }
    }, () => { if (!initialised) { initialised = true; setLoaded(true); } });

    const unsubSubs = onSnapshot(SUBS_DOC, snap => {
      if (snap.exists()) {
        const data = snap.data().data;
        if (Array.isArray(data)) setSubs(data);
      }
    });

    const unsubBonuses = onSnapshot(BONUS_DOC, snap => {
      if (snap.exists()) setWeekBonuses(snap.data() || {});
    });

    return () => { clearTimeout(safetyTimer); unsubUsers(); unsubSubs(); unsubBonuses(); };
  },[]);

  const saveUsers = async u => { setUsers(u); await setDoc(USERS_DOC, { data: u }); };
  const saveSubs  = async s => { setSubs(s);  await setDoc(SUBS_DOC,  { data: s }); };
  const saveWeekBonus = async (week, bonus) => {
    const next = { ...weekBonuses, [week]: bonus };
    setWeekBonuses(next);
    await setDoc(BONUS_DOC, next);
  };

  const showToast = (msg, type="ok") => {
    setToast({msg,type});
    setTimeout(()=>setToast(null),3200);
  };

  // 登入
  const handleLogin = (uid, pw) => {
    if (uid==="admin" && pw===ADMIN_ACCOUNT.password) {
      setMe(ADMIN_ACCOUNT); sfx.login(); setScreen("main"); setTab("board"); return;
    }
    const u = users.find(x=>x.id===uid);
    if (!u) { sfx.error(); showToast("找不到此帳號","err"); return; }
    // 尚未設定密碼 → 進首次設定流程
    if (!u.setupDone) {
      setMe(u); sfx.select(); setScreen("setup"); return;
    }
    if (u.password !== pw) { sfx.error(); showToast("密碼錯誤！","err"); return; }
    setMe(u); sfx.login(); setScreen("main"); setTab("board");
  };

  // 首次設定完成
  const handleSetupDone = (updatedUser) => {
    // 先立刻切換畫面，storage 在背景儲存不卡 UI
    const next = users.map(u=>u.id===updatedUser.id ? updatedUser : u);
    setUsers(next);
    setMe(updatedUser);
    sfx.setup();
    showToast(`歡迎加入，${updatedUser.realName}！`,"ok");
    setScreen("main");
    setTab("board");
    // 背景儲存
    saveUsers(next);
  };

  // 上傳任務
  const handleSubmit = async (taskId, imgData, note) => {
    const now = new Date();
    const day = now.getDay();
    const hour = now.getHours();
    if (day === 0 && hour === 23) {
      showToast("🔧 系統維護中（週日23:00–24:00），暫停上傳","err");
      return false;
    }
    const week = getSubmitWeek(now.toISOString());
    const task = TASKS.find(t=>t.id===taskId);
    const dynBonus = weekBonuses[week] !== undefined ? weekBonuses[week] : (WEEKS.find(w=>w.week===week)?.bonus ?? null);
    const xp = (dynBonus?.taskId===taskId) ? dynBonus.multiplier : task.xp;
    const entry = { id:Date.now()+"", userId:me.id, taskId, week, ts:now.toISOString(), imgData, note, xp };
    const next = [...subs, entry];
    await saveSubs(next);
    sfx.taskSfx(taskId);
    showToast(`✅ 獲得 ${xp} XP！（第 ${week} 週）`,"ok");
    return true;
  };

  const curWeek = getCurrentWeek();
  const getBonus = w => weekBonuses[w] !== undefined ? weekBonuses[w] : (WEEKS.find(x=>x.week===w)?.bonus ?? null);
  const wBonus  = getBonus(curWeek);

  if (!loaded) return (
    <div style={{height:"100vh",background:"#1A1A2E",display:"flex",alignItems:"center",justifyContent:"center"}}>
      <span style={{color:"#F8C500",fontFamily:"monospace",fontSize:16,letterSpacing:2}}>LOADING...</span>
    </div>
  );

  return (
    <div style={{minHeight:"100vh",background:"#F5F0E8",fontFamily:"'Noto Sans TC',sans-serif",
      backgroundImage:"repeating-linear-gradient(0deg,transparent,transparent 39px,rgba(0,0,0,.05) 39px,rgba(0,0,0,.05) 40px),repeating-linear-gradient(90deg,transparent,transparent 39px,rgba(0,0,0,.05) 39px,rgba(0,0,0,.05) 40px)"}}>

      {toast && <Toast msg={toast.msg} type={toast.type} />}

      {screen==="press" && <PressStart onStart={()=>{sfx.select();setScreen("login");}} />}
      {screen==="login" && <LoginScreen users={users} onLogin={handleLogin} showToast={showToast} sfx={sfx} />}
      {screen==="setup" && me && (
        <FirstSetup user={me} users={users} onDone={handleSetupDone} sfx={sfx} showToast={showToast} />
      )}
      {screen==="main" && me && (
        <MainApp
          me={me} setMe={setMe}
          users={users} saveUsers={saveUsers}
          subs={subs} saveSubs={saveSubs}
          tab={tab} setTab={setTab}
          curWeek={curWeek} wBonus={wBonus}
          weekBonuses={weekBonuses} getBonus={getBonus} saveWeekBonus={saveWeekBonus}
          onSubmit={handleSubmit}
          onLogout={()=>{setScreen("login");setMe(null);}}
          showToast={showToast} sfx={sfx}
        />
      )}
    </div>
  );
}

// ══════════════════════════════════════════
// PRESS START
// ══════════════════════════════════════════
function PressStart({onStart}) {
  const [blink,setBlink]=useState(true);
  useEffect(()=>{const id=setInterval(()=>setBlink(b=>!b),550);return()=>clearInterval(id);},[]);
  return (
    <div style={{position:"fixed",inset:0,background:"#1A1A2E",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",zIndex:9999}}>
      <div style={{fontSize:"clamp(52px,10vw,90px)",marginBottom:16,animation:"bop .9s ease infinite alternate"}}>🍄⭐🎮</div>
      <h1 style={{fontWeight:900,fontSize:"clamp(22px,5vw,50px)",color:"#fff",textShadow:"4px 4px 0 #F8C500",textAlign:"center",padding:"0 20px",marginBottom:6,lineHeight:1.2}}>
        超級瑪利歐破關大作戰
      </h1>
      <p style={{fontFamily:"monospace",fontSize:"clamp(10px,2vw,13px)",color:"#F8C500",marginBottom:44,textAlign:"center"}}>
        嘉南執行團隊｜5–6月招募競賽 2026
      </p>
      <button onClick={onStart}
        style={{fontFamily:"monospace",fontWeight:900,fontSize:14,background:"#F8C500",color:"#000",border:"3px solid #fff",padding:"16px 42px",cursor:"pointer",boxShadow:"0 0 0 3px #F8C500,6px 6px 0 #fff",opacity:blink?1:.25,transition:"opacity .1s"}}>
        [ PRESS START ]
      </button>
      <style>{`@keyframes bop{from{transform:translateY(0)}to{transform:translateY(-14px)}}`}</style>
    </div>
  );
}

// ══════════════════════════════════════════
// LOGIN
// ══════════════════════════════════════════
function LoginScreen({users, onLogin, showToast, sfx}) {
  const [selId,setSelId]=useState("");
  const [pw,setPw]=useState("");
  const selUser = users.find(u=>u.id===selId);
  const isFirstTime = selUser && !selUser.setupDone;

  return (
    <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",padding:20}}>
      <div style={{background:"#fff",border:"3px solid #000",boxShadow:"8px 8px 0 #000",padding:"32px 26px",maxWidth:420,width:"100%"}}>
        <div style={{textAlign:"center",marginBottom:22}}>
          <div style={{fontSize:44,marginBottom:8}}>🔐</div>
          <div style={{fontFamily:"monospace",fontWeight:900,fontSize:13,color:"#1A1A2E"}}>SELECT YOUR CHARACTER</div>
        </div>

        {/* 角色選擇 */}
        <label style={{display:"block",fontWeight:700,fontSize:13,marginBottom:6}}>選擇你的小隊角色</label>
        <select value={selId} onChange={e=>{setSelId(e.target.value);sfx.select();}}
          style={{width:"100%",padding:10,border:"3px solid #000",fontSize:15,fontWeight:700,background:"#F5F0E8",marginBottom:14}}>
          <option value="">── 選擇角色 ──</option>
          <option value="admin">👑 大C（管理者）</option>
          <optgroup label="🔴 瑪利歐紅隊">
            {users.filter(u=>u.team==="red").map(u=>(
              <option key={u.id} value={u.id}>
                {u.setupDone ? "✅ " : "❓ "}{u.name}{u.realName?" ("+u.realName+")":""}
              </option>
            ))}
          </optgroup>
          <optgroup label="🟢 路易吉綠隊">
            {users.filter(u=>u.team==="green").map(u=>(
              <option key={u.id} value={u.id}>
                {u.setupDone && u.charId ? getChar(u.charId).emoji+" " : "❓ "}{u.name}{u.realName?" ("+u.realName+")":""}
              </option>
            ))}
          </optgroup>
        </select>

        {/* 首次提示 */}
        {isFirstTime && (
          <div style={{background:"#FFF9E0",border:"2px solid #F8C500",padding:"10px 14px",marginBottom:14,fontSize:13,fontWeight:700}}>
            🎮 首次登入！點擊下方按鈕進行角色設定
          </div>
        )}

        {/* 密碼 */}
        {!isFirstTime && (
          <div style={{marginBottom:16}}>
            <label style={{display:"block",fontWeight:700,fontSize:13,marginBottom:6}}>密碼</label>
            <input type="password" value={pw} onChange={e=>setPw(e.target.value)}
              onKeyDown={e=>e.key==="Enter"&&onLogin(selId,pw)}
              placeholder="輸入密碼" style={{width:"100%",padding:10,border:"3px solid #000",fontSize:15,boxSizing:"border-box"}} />
          </div>
        )}

        <button onClick={()=>onLogin(selId,pw)}
          style={{width:"100%",background:"#1A1A2E",color:"#F8C500",border:"3px solid #F8C500",padding:14,fontFamily:"monospace",fontSize:13,cursor:"pointer",fontWeight:900,boxShadow:"4px 4px 0 #F8C500"}}>
          {isFirstTime ? "▶ 開始首次設定" : "▶ 進入戰場"}
        </button>

      </div>
    </div>
  );
}

// ══════════════════════════════════════════
// 首次登入設定
// ══════════════════════════════════════════
function FirstSetup({user, users, onDone, sfx, showToast}) {
  const [step,setStep]       = useState(1);
  const [realName,setRealName]= useState("");
  const [charId,setCharId]   = useState("");
  const [pw1,setPw1]         = useState("");
  const [pw2,setPw2]         = useState("");
  const [done,setDone]       = useState(false);

  const char = charId ? getChar(charId) : null;

  const goStep2 = () => {
    if (!realName.trim()) { showToast("請輸入你的真實姓名","err"); return; }
    sfx.select(); setStep(2);
  };
  const goStep3 = () => {
    if (!charId) { showToast("請選擇一個角色","err"); return; }
    sfx.select(); setStep(3);
  };
  const finish = () => {
    if (done) return;
    if (!realName.trim()) { showToast("請輸入真實姓名","err"); return; }
    if (!charId) { showToast("請選擇角色","err"); return; }
    if (!pw1 || pw1.length<4) { showToast("密碼至少4位","err"); return; }
    if (pw1!==pw2) { showToast("兩次密碼不一致","err"); sfx.error(); return; }
    setDone(true);
    onDone({ ...user, realName:realName.trim(), charId, password:pw1, setupDone:true });
  };

  return (
    <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",padding:20,background:"#1A1A2E",
      backgroundImage:"radial-gradient(circle at 20% 50%,rgba(229,34,34,.15) 0%,transparent 50%),radial-gradient(circle at 80% 50%,rgba(45,173,63,.15) 0%,transparent 50%)"}}>
      <div style={{background:"#fff",border:"3px solid #F8C500",boxShadow:"8px 8px 0 #F8C500",padding:"28px 24px",maxWidth:500,width:"100%"}}>

        {/* 步驟指示 */}
        <div style={{display:"flex",gap:0,marginBottom:22,border:"2px solid #000",overflow:"hidden"}}>
          {["①真實姓名","②選擇角色","③設定密碼"].map((s,i)=>(
            <div key={i} style={{flex:1,padding:"8px 4px",textAlign:"center",fontSize:12,fontWeight:700,
              background:step===i+1?"#1A1A2E":step>i+1?"#2DAD3F":"#fff",
              color:step===i+1?"#F8C500":step>i+1?"#fff":"#aaa",
              borderRight:i<2?"2px solid #000":"none"}}>
              {step>i+1?"✓ ":""}{s}
            </div>
          ))}
        </div>

        <div style={{textAlign:"center",marginBottom:6,fontSize:13,color:"#888",fontFamily:"monospace"}}>
          🎮 首次登入設定｜{user.name}
        </div>

        {/* STEP 1: 真實姓名 */}
        {step===1 && (
          <div>
            <h2 style={{fontWeight:900,fontSize:20,marginBottom:4,color:"#1A1A2E"}}>輸入你的真實姓名</h2>
            <p style={{fontSize:13,color:"#666",marginBottom:20,lineHeight:1.8}}>
              這個名字將顯示在排行榜上，<br/>搭配你的小隊名稱 <strong style={{color:"#1A1A2E"}}>「{user.name}」</strong> 一起亮相！
            </p>
            <input value={realName} onChange={e=>setRealName(e.target.value)}
              onKeyDown={e=>e.key==="Enter"&&goStep2()}
              placeholder="例如：小明" maxLength={10}
              style={{width:"100%",padding:12,border:"3px solid #000",fontSize:18,fontWeight:700,boxSizing:"border-box",marginBottom:4}} />
            {realName && (
              <div style={{fontSize:13,color:"#888",marginBottom:12}}>
                顯示名稱將為：<strong style={{color:"#E52222"}}>{user.name}・{realName}</strong>
              </div>
            )}
            <button onClick={goStep2}
              style={{width:"100%",background:"#1A1A2E",color:"#F8C500",border:"3px solid #F8C500",padding:13,fontFamily:"monospace",fontSize:13,cursor:"pointer",fontWeight:900,boxShadow:"4px 4px 0 #F8C500",marginTop:8}}>
              下一步 ▶
            </button>
          </div>
        )}

        {/* STEP 2: 選角色 */}
        {step===2 && (
          <div>
            <h2 style={{fontWeight:900,fontSize:20,marginBottom:4,color:"#1A1A2E"}}>選擇你的戰鬥角色</h2>
            <p style={{fontSize:13,color:"#666",marginBottom:16}}>馬力歐賽車15位角色，選一個代表你！</p>
            <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8,marginBottom:16,maxHeight:360,overflowY:"auto"}}>
              {CHARACTERS.map(c=>(
                <button key={c.id} onClick={()=>{setCharId(c.id);sfx.select();}}
                  style={{border:`3px solid ${charId===c.id?c.color:"#ccc"}`,padding:"10px 6px",background:charId===c.id?c.bg:"#fff",cursor:"pointer",
                    textAlign:"center",boxShadow:charId===c.id?`3px 3px 0 ${c.color}`:"none",transition:"all .15s",fontFamily:"'Noto Sans TC',sans-serif"}}>
                  <div style={{display:"flex",justifyContent:"center",marginBottom:4}}><CharAvatar charId={c.id} size={52}/></div>
                  <div style={{fontWeight:900,fontSize:10,color:charId===c.id?c.color:"#333"}}>{c.nameZh||c.name}</div>
                  <div style={{fontSize:9,color:"#888",marginTop:1,lineHeight:1.3}}>{c.desc}</div>
                </button>
              ))}
            </div>
            {char && (
              <div style={{background:char.bg,border:`2px solid ${char.color}`,padding:"10px 14px",marginBottom:12,display:"flex",gap:12,alignItems:"center"}}>
                <CharAvatar charId={char.id} size={52}/>
                <div><div style={{fontWeight:900,fontSize:15,color:char.color}}>{char.nameZh||char.name}</div><div style={{fontSize:12,color:"#666"}}>{char.desc}</div></div>
              </div>
            )}
            <div style={{display:"flex",gap:8}}>
              <button onClick={()=>setStep(1)} style={{padding:"12px 20px",border:"2px solid #ccc",background:"#fff",cursor:"pointer",fontSize:13,fontWeight:700}}>← 返回</button>
              <button onClick={goStep3} style={{flex:1,background:"#1A1A2E",color:"#F8C500",border:"3px solid #F8C500",padding:12,fontFamily:"monospace",fontSize:13,cursor:"pointer",fontWeight:900,boxShadow:"4px 4px 0 #F8C500"}}>
                選好了 ▶
              </button>
            </div>
          </div>
        )}

        {/* STEP 3: 設定密碼 */}
        {step===3 && (
          <div>
            <h2 style={{fontWeight:900,fontSize:20,marginBottom:4,color:"#1A1A2E"}}>設定你的密碼</h2>
            <p style={{fontSize:13,color:"#666",marginBottom:20}}>密碼至少4位，請記住它！</p>

            {char && (
              <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:18,padding:"10px 14px",background:char.bg,border:`2px solid ${char.color}`}}>
                <CharAvatar charId={char.id} size={52}/>
                <div>
                  <div style={{fontWeight:900,fontSize:14}}>{char.nameZh||char.name}</div>
                  <div style={{fontSize:13,color:"#555"}}>{user.name}・{realName}</div>
                </div>
              </div>
            )}

            <label style={{display:"block",fontWeight:700,fontSize:13,marginBottom:6}}>設定密碼</label>
            <input type="password" value={pw1} onChange={e=>setPw1(e.target.value)}
              placeholder="至少4位" style={{width:"100%",padding:10,border:"3px solid #000",fontSize:15,boxSizing:"border-box",marginBottom:12}} />
            <label style={{display:"block",fontWeight:700,fontSize:13,marginBottom:6}}>確認密碼</label>
            <input type="password" value={pw2} onChange={e=>setPw2(e.target.value)}
              onKeyDown={e=>e.key==="Enter"&&finish()}
              placeholder="再輸入一次" style={{width:"100%",padding:10,border:`3px solid ${pw2&&pw1!==pw2?"#E52222":"#000"}`,fontSize:15,boxSizing:"border-box",marginBottom:6}} />
            {pw2 && pw1!==pw2 && <div style={{color:"#E52222",fontSize:12,marginBottom:10}}>密碼不一致</div>}

            <div style={{display:"flex",gap:8,marginTop:12}}>
              <button onClick={()=>setStep(2)} style={{padding:"12px 20px",border:"2px solid #ccc",background:"#fff",cursor:"pointer",fontSize:13,fontWeight:700}}>← 返回</button>
              <button onClick={finish} disabled={done}
                style={{flex:1,background:done?"#aaa":"#2DAD3F",color:"#fff",border:"3px solid #000",padding:12,fontFamily:"monospace",fontSize:13,cursor:done?"not-allowed":"pointer",fontWeight:900,boxShadow:done?"none":"4px 4px 0 #000"}}>
                {done ? "⏳ 處理中..." : "🎮 開始冒險！"}
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

// ══════════════════════════════════════════
// MAIN APP
// ══════════════════════════════════════════
function MainApp({me,setMe,users,saveUsers,subs,saveSubs,tab,setTab,curWeek,wBonus,weekBonuses,getBonus,saveWeekBonus,onSubmit,onLogout,showToast,sfx}) {
  const char = getChar(me.charId||"mario");
  const tabs = [
    {id:"board",  label:"🏆 戰況"},
    {id:"rank",   label:"🥇 排行"},
    {id:"submit", label:"📤 上傳"},
    {id:"history",label:"📋 記錄"},
    {id:"rules",  label:"📜 規則"},
    {id:"manual", label:"📖 說明"},
    {id:"monitor", label:"📊 分析"},
    ...(me.isAdmin?[{id:"admin",label:"👑 管理"}]:[]),
  ];
  const displayName = me.isAdmin ? "大C（管理者）" : `${me.name}・${me.realName||"?"}`;

  return (
    <div>
      {/* HEADER */}
      <div style={{background:"#1A1A2E",color:"#F8C500",padding:"10px 14px",display:"flex",alignItems:"center",justifyContent:"space-between",borderBottom:"3px solid #F8C500",position:"sticky",top:0,zIndex:100}}>
        <div style={{display:"flex",alignItems:"center",gap:10}}>
          <div style={{lineHeight:1}}><CharAvatar charId={me.charId||"mario"} size={40}/></div>
          <div>
            <div style={{fontFamily:"monospace",fontSize:"clamp(8px,1.5vw,11px)",opacity:.7}}>超級瑪利歐破關大作戰</div>
            <div style={{fontWeight:900,fontSize:"clamp(12px,2.5vw,15px)",color:"#fff"}}>{displayName}</div>
          </div>
        </div>
        <div style={{display:"flex",gap:8,alignItems:"center"}}>
          <div style={{background:"#E52222",color:"#fff",padding:"3px 10px",fontSize:11,fontWeight:900,border:"2px solid #fff",fontFamily:"monospace"}}>W{curWeek}</div>
          <button onClick={onLogout} style={{background:"transparent",border:"2px solid #F8C500",color:"#F8C500",padding:"4px 10px",fontSize:11,cursor:"pointer",fontFamily:"monospace"}}>LOGOUT</button>
        </div>
      </div>

      {wBonus && (
        <div style={{background:"#E52222",color:"#fff",textAlign:"center",padding:"7px 14px",fontWeight:900,fontSize:13,borderBottom:"3px solid #000"}}>
          🔥 本週W{curWeek}加權：{wBonus.label}
        </div>
      )}

      {/* TABS */}
      <div style={{display:"flex",overflowX:"auto",background:"#fff",borderBottom:"3px solid #000"}}>
        {tabs.map(t=>(
          <button key={t.id} onClick={()=>setTab(t.id)}
            style={{flexShrink:0,padding:"10px 13px",border:"none",borderRight:"2px solid #ddd",cursor:"pointer",fontWeight:700,fontSize:"clamp(10px,2vw,13px)",fontFamily:"'Noto Sans TC',sans-serif",
              background:tab===t.id?"#1A1A2E":"#fff",color:tab===t.id?"#F8C500":"#444",whiteSpace:"nowrap"}}>
            {t.label}
          </button>
        ))}
      </div>

      {/* CONTENT */}
      <div style={{maxWidth:920,margin:"0 auto",padding:"18px 14px 80px"}}>
        {tab==="board"   && <BoardTab   users={users} subs={subs} curWeek={curWeek} />}
        {tab==="rank"    && <RankTab    users={users} subs={subs} curWeek={curWeek} />}
        {tab==="submit"  && <SubmitTab  me={me} onSubmit={onSubmit} curWeek={curWeek} getBonus={getBonus} showToast={showToast} />}
        {tab==="history" && <HistoryTab me={me} users={users} subs={subs} saveSubs={saveSubs} showToast={showToast} sfx={sfx} />}
        {tab==="rules"   && <RulesTab   curWeek={curWeek} />}
        {tab==="manual"  && <ManualTab />}
        {tab==="monitor" && <MonitorBoard users={users} subs={subs} curWeek={curWeek} />}
        {tab==="admin"   && me.isAdmin && <AdminTab users={users} saveUsers={saveUsers} subs={subs} saveSubs={saveSubs} weekBonuses={weekBonuses} getBonus={getBonus} saveWeekBonus={saveWeekBonus} showToast={showToast} sfx={sfx} />}
      </div>
    </div>
  );
}

// ══════════════════════════════════════════
// BOARD TAB
// ══════════════════════════════════════════
function BoardTab({users, subs, curWeek}) {
  const [vw, setVw] = useState(curWeek);
  const teamXP = (team, week) => {
    const ids = users.filter(u=>u.team===team).map(u=>u.id);
    return subs.filter(s=>ids.includes(s.userId)&&s.week===week).reduce((a,b)=>a+b.xp,0);
  };
  const memberXP = (uid, week) => subs.filter(s=>s.userId===uid&&s.week===week).reduce((a,b)=>a+b.xp,0);
  const redXP   = teamXP("red",   vw);
  const greenXP = teamXP("green", vw);
  const total   = redXP+greenXP||1;
  const redPct  = Math.round(redXP/total*100);

  // 人均戰力固定除以 27（兩隊相同，不管登入人數）
  const FIXED_DIVISOR = 27;
  const redCount   = FIXED_DIVISOR;
  const greenCount = FIXED_DIVISOR;
  const redAvg   = (redXP / FIXED_DIVISOR).toFixed(1);
  const greenAvg = (greenXP / FIXED_DIVISOR).toFixed(1);

  return (
    <div>
      {/* 週切換 */}
      <div style={{display:"flex",gap:6,marginBottom:14,flexWrap:"wrap"}}>
        {WEEKS.map(w=>(
          <button key={w.week} onClick={()=>setVw(w.week)}
            style={{padding:"5px 13px",border:"2px solid #000",cursor:"pointer",fontWeight:700,fontSize:12,fontFamily:"monospace",
              background:vw===w.week?"#1A1A2E":"#fff",color:vw===w.week?"#F8C500":"#000"}}>
            W{w.week}{w.week===curWeek?" ◀":""}
          </button>
        ))}
      </div>

      {/* 進度條 */}
      <div style={{border:"3px solid #000",overflow:"hidden",height:46,display:"grid",gridTemplateColumns:`${redPct}fr auto ${100-redPct}fr`,marginBottom:14}}>
        <div style={{background:"#E52222",display:"flex",alignItems:"center",padding:"0 12px",color:"#fff",fontFamily:"monospace",fontWeight:900,fontSize:"clamp(10px,2vw,13px)"}}>
          🔴 {redXP}pt
        </div>
        <div style={{background:"#F8C500",color:"#000",display:"flex",alignItems:"center",padding:"0 8px",fontFamily:"monospace",fontSize:11,borderLeft:"2px solid #000",borderRight:"2px solid #000",whiteSpace:"nowrap"}}>VS</div>
        <div style={{background:"#2DAD3F",display:"flex",alignItems:"center",justifyContent:"flex-end",padding:"0 12px",color:"#fff",fontFamily:"monospace",fontWeight:900,fontSize:"clamp(10px,2vw,13px)"}}>
          {greenXP}pt 🟢
        </div>
      </div>

      {/* 表格 */}
      <table style={{width:"100%",borderCollapse:"collapse",border:"3px solid #000",marginBottom:18}}>
        <thead>
          <tr style={{background:"#1A1A2E"}}>
            {["排名","隊伍","總分","基準","人均戰力"].map(h=>(
              <th key={h} style={{color:"#F8C500",padding:"8px 6px",fontSize:11,fontFamily:"monospace",border:"2px solid #000",textAlign:"center"}}>{h}</th>
            ))}
          </tr>
        </thead>
        <tbody>
          {[
            {team:"red",   label:"🔴 瑪利歐紅隊", xp:redXP,   avg:redAvg,   cnt:redCount,   bg:"#FFF5F5"},
            {team:"green", label:"🟢 路易吉綠隊",  xp:greenXP, avg:greenAvg, cnt:greenCount, bg:"#F0FFF4"},
          ].sort((a,b)=>b.avg-a.avg).map((r,i)=>(
            <tr key={r.team} style={{background:r.bg}}>
              <td style={{textAlign:"center",border:"2px solid #ccc",padding:10,fontFamily:"monospace",fontSize:20,fontWeight:900}}>{i+1}</td>
              <td style={{textAlign:"center",border:"2px solid #ccc",padding:10,fontWeight:900,fontSize:14}}>{r.label}</td>
              <td style={{textAlign:"center",border:"2px solid #ccc",padding:10,fontWeight:900,fontSize:20,color:"#E52222"}}>{r.xp}</td>
              <td style={{textAlign:"center",border:"2px solid #ccc",padding:10}}>{r.cnt}</td>
              <td style={{textAlign:"center",border:"2px solid #ccc",padding:10,fontWeight:900,fontSize:16,color:"#1565C0"}}>{r.avg}</td>
            </tr>
          ))}
        </tbody>
      </table>

      {/* 個人牌 */}
      {["red","green"].map(team=>{
        const squads = [...new Set(users.filter(u=>u.team===team).map(u=>u.squad||"（未分配）"))].sort();
        const color = team==="red"?"#E52222":"#2DAD3F";
        return (
          <div key={team} style={{marginBottom:16}}>
            <div style={{fontWeight:900,fontSize:15,marginBottom:10,color}}>
              {team==="red"?"🔴 瑪利歐紅隊成員":"🟢 路易吉綠隊成員"}
            </div>
            {squads.map(sq=>(
              <div key={sq} style={{marginBottom:12}}>
                <div style={{fontSize:12,fontWeight:700,color:"#555",background:"#f0f0f0",padding:"4px 10px",borderLeft:`3px solid ${color}`,marginBottom:8}}>🏷️ {sq}</div>
                <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(130px,1fr))",gap:8}}>
                  {users.filter(u=>u.team===team&&(u.squad||"（未分配）")===sq).map(u=>{
                    const xp = memberXP(u.id, vw);
                    const cnt = subs.filter(s=>s.userId===u.id&&s.week===vw).length;
                    return (
                      <div key={u.id} style={{border:`3px solid ${color}`,padding:"12px 8px",background:"#fff",boxShadow:`3px 3px 0 ${color}`,textAlign:"center"}}>
                        <div style={{display:"flex",justifyContent:"center",marginBottom:4}}><CharAvatar charId={u.charId||"mario"} size={36}/></div>
                        <div style={{fontWeight:900,fontSize:14,color,marginBottom:2}}>{u.realName||u.name}</div>
                        <div style={{fontSize:10,color:"#aaa",marginBottom:6}}>{u.name}</div>
                        <div style={{fontFamily:"monospace",fontSize:24,fontWeight:900,color}}>{xp}</div>
                        <div style={{fontSize:11,color:"#aaa",marginTop:2}}>{cnt}筆</div>
                      </div>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>
        );
      })}
    </div>
  );
}

// ══════════════════════════════════════════
// RANK TAB（個人前10 + 全期）
// ══════════════════════════════════════════
function RankTab({users, subs, curWeek}) {
  const [vw, setVw] = useState(curWeek);
  const [mode, setMode] = useState("week"); // week | alltime

  const getMemberXP = (uid, week) => subs.filter(s=>s.userId===uid&&(week==="all"||s.week===week)).reduce((a,b)=>a+b.xp,0);

  const ranked = [...users].map(u=>({
    ...u,
    xp: getMemberXP(u.id, mode==="week"?vw:"all"),
    submits: subs.filter(s=>s.userId===u.id&&(mode==="week"?s.week===vw:true)).length,
  })).sort((a,b)=>b.xp-a.xp).slice(0,10);

  const medals = ["🥇","🥈","🥉","4️⃣","5️⃣","6️⃣","7️⃣","8️⃣","9️⃣","🔟"];

  return (
    <div>
      {/* 模式切換 */}
      <div style={{display:"flex",gap:0,border:"2px solid #000",marginBottom:14,overflow:"hidden",maxWidth:360}}>
        <button onClick={()=>setMode("week")} style={{flex:1,padding:"9px 0",border:"none",borderRight:"2px solid #000",cursor:"pointer",fontWeight:700,fontSize:13,background:mode==="week"?"#1A1A2E":"#fff",color:mode==="week"?"#F8C500":"#000"}}>本週排行</button>
        <button onClick={()=>setMode("alltime")} style={{flex:1,padding:"9px 0",border:"none",cursor:"pointer",fontWeight:700,fontSize:13,background:mode==="alltime"?"#1A1A2E":"#fff",color:mode==="alltime"?"#F8C500":"#000"}}>全期累積</button>
      </div>

      {mode==="week" && (
        <div style={{display:"flex",gap:6,marginBottom:14,flexWrap:"wrap"}}>
          {WEEKS.map(w=>(
            <button key={w.week} onClick={()=>setVw(w.week)}
              style={{padding:"5px 12px",border:"2px solid #000",cursor:"pointer",fontWeight:700,fontSize:12,fontFamily:"monospace",background:vw===w.week?"#1A1A2E":"#fff",color:vw===w.week?"#F8C500":"#000"}}>
              W{w.week}{w.week===curWeek?" ◀":""}
            </button>
          ))}
        </div>
      )}

      {/* 前三名大卡 */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10,marginBottom:16}}>
        {ranked.slice(0,3).map((u,i)=>{
          const c = getChar(u.charId||"mario");
          const podiumH = [120,100,80][i];
          return (
            <div key={u.id} style={{textAlign:"center"}}>
              <div style={{background:u.team==="red"?"#FFE0E0":"#E0FFE4",border:`3px solid ${u.team==="red"?"#E52222":"#2DAD3F"}`,padding:"14px 8px",boxShadow:`4px 4px 0 ${u.team==="red"?"#E52222":"#2DAD3F"}`,height:podiumH+100,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center"}}>
                <div style={{fontSize:10,fontFamily:"monospace",marginBottom:4,color:"#888"}}>#{i+1}</div>
                <div style={{display:"flex",justifyContent:"center",marginBottom:4}}><CharAvatar charId={u.charId||"mario"} size={56}/></div>
                <div style={{fontSize:12,fontWeight:900}}>{u.realName||u.name}</div>
                <div style={{fontSize:10,color:"#888"}}>{u.name}</div>
                <div style={{fontFamily:"monospace",fontSize:24,fontWeight:900,color:u.team==="red"?"#E52222":"#2DAD3F",marginTop:4}}>{u.xp}</div>
                <div style={{fontSize:10,color:"#aaa"}}>XP</div>
              </div>
              <div style={{background:["#F8C500","#BDBDBD","#A1887F"][i],height:podiumH,border:"2px solid #000",display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"monospace",fontSize:["28px","22px","18px"][i],fontWeight:900}}>
                {medals[i]}
              </div>
            </div>
          );
        })}
      </div>

      {/* 4–10名列表 */}
      <div style={{background:"#1A1A2E",border:"3px solid #F8C500",padding:16,boxShadow:"5px 5px 0 #F8C500"}}>
        <div style={{color:"#F8C500",fontFamily:"monospace",fontSize:12,fontWeight:900,marginBottom:12}}>
          {mode==="week"?`⚔️ W${vw} 個人積分前10名`:"👑 全期累積排行榜 TOP 10"}
        </div>
        {ranked.map((u,i)=>{
          const c = getChar(u.charId||"mario");
          return (
            <div key={u.id} style={{display:"flex",alignItems:"center",gap:10,padding:"8px 10px",marginBottom:6,
              background:i===0?"rgba(248,197,0,.2)":i===1?"rgba(200,200,200,.12)":i===2?"rgba(180,100,0,.1)":"transparent",
              border:i===0?"1px solid rgba(248,197,0,.5)":"1px solid transparent"}}>
              <div style={{fontFamily:"monospace",fontSize:18,minWidth:28,color:["#F8C500","#BDBDBD","#CD7F32"][i]||"#fff"}}>{medals[i]}</div>
              <div><CharAvatar charId={u.charId||"mario"} size={40}/></div>
              <div style={{flex:1}}>
                <div style={{color:u.team==="red"?"#FF8080":"#80FF80",fontWeight:700,fontSize:14}}>{u.realName||u.name}</div>
                <div style={{color:"#aaa",fontSize:11}}>{u.name} · {u.submits}筆</div>
              </div>
              <div style={{fontFamily:"monospace",fontSize:22,fontWeight:900,color:"#F8C500"}}>{u.xp}</div>
            </div>
          );
        })}
        {ranked.length===0 && <div style={{color:"#888",textAlign:"center",padding:20,fontSize:13}}>本週尚無記錄</div>}
      </div>
    </div>
  );
}

// ══════════════════════════════════════════
// SUBMIT TAB
// ══════════════════════════════════════════
function SubmitTab({me, onSubmit, curWeek, getBonus, showToast}) {
  const [taskId,setTaskId]   = useState("");
  const [note,setNote]       = useState("");
  const [imgData,setImgData] = useState(null);
  const [imgPrev,setImgPrev] = useState(null);
  const [busy,setBusy]       = useState(false);
  const fileRef = useRef();

  const curBonus = getBonus(curWeek);
  const task   = TASKS.find(t=>t.id===taskId);
  const effXP  = task ? (curBonus?.taskId===taskId ? curBonus.multiplier : task.xp) : 0;
  const isBonus = task && curBonus?.taskId===taskId;

  const handleFile = e => {
    const f = e.target.files[0];
    if (!f) return;
    if (f.size>3*1024*1024) { showToast("圖片請勿超過3MB","err"); return; }
    const r = new FileReader();
    r.onload = ev => { setImgData(ev.target.result); setImgPrev(ev.target.result); };
    r.readAsDataURL(f);
  };

  const submit = async () => {
    if (!taskId) { showToast("請選擇任務類型","err"); return; }
    if (!imgData) { showToast("截圖為必填！","err"); return; }
    setBusy(true);
    const ok = await onSubmit(taskId, imgData, note);
    if (ok) { setTaskId(""); setNote(""); setImgData(null); setImgPrev(null); if(fileRef.current) fileRef.current.value=""; }
    setBusy(false);
  };

  const char = getChar(me.charId||"mario");

  return (
    <div>
      <div style={{background:"#fff",border:"3px solid #000",boxShadow:"5px 5px 0 #000",padding:20,marginBottom:14}}>
        <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:18}}>
          <div style={{fontSize:38}}>{char.emoji}</div>
          <div>
            <div style={{fontWeight:900,fontSize:16}}>📤 上傳任務成果</div>
            <div style={{fontSize:12,color:"#888"}}>{me.name}・{me.realName}</div>
          </div>
        </div>

        {/* 任務選擇 */}
        <label style={{display:"block",fontWeight:700,fontSize:13,marginBottom:8}}>選擇任務類型 *</label>
        <div style={{display:"grid",gridTemplateColumns:"repeat(2,1fr)",gap:8,marginBottom:14}}>
          {TASKS.map(t=>{
            const b = curBonus?.taskId===t.id;
            const dx = b ? curBonus.multiplier : t.xp;
            const sel = taskId===t.id;
            return (
              <button key={t.id} onClick={()=>setTaskId(t.id)}
                style={{padding:"10px 8px",border:`3px solid ${sel?"#1A1A2E":"#ddd"}`,background:sel?"#1A1A2E":"#fff",
                  color:sel?"#F8C500":"#000",cursor:"pointer",textAlign:"left",display:"flex",alignItems:"center",gap:8,
                  boxShadow:sel?"3px 3px 0 #F8C500":"none",fontFamily:"'Noto Sans TC',sans-serif"}}>
                <span style={{fontSize:20}}>{t.emoji}</span>
                <span>
                  <div style={{fontWeight:900,fontSize:13}}>{t.label}</div>
                  <div style={{fontFamily:"monospace",fontSize:10,color:b?"#E52222":sel?"#F8C500":"#999"}}>
                    +{dx} XP{b?" 🔥加權":""}
                  </div>
                </span>
              </button>
            );
          })}
        </div>

        {/* XP 預覽 */}
        {task && (
          <div style={{background:isBonus?"#FFF0F0":"#F0FFF4",border:`2px solid ${isBonus?"#E52222":"#2DAD3F"}`,padding:"10px 14px",marginBottom:14,display:"flex",alignItems:"center",gap:12}}>
            <div style={{fontFamily:"monospace",fontSize:30,fontWeight:900,color:isBonus?"#E52222":"#2DAD3F"}}>+{effXP}</div>
            <div style={{fontSize:13}}><strong>{task.label}</strong>{isBonus&&<span style={{color:"#E52222",marginLeft:6}}>🔥 本週加權！</span>}</div>
          </div>
        )}

        {/* 截圖上傳 */}
        <label style={{display:"block",fontWeight:700,fontSize:13,marginBottom:8}}>
          截圖證明 * <span style={{fontWeight:400,color:"#888",fontSize:12}}>（必填才能得分）</span>
        </label>
        <div onClick={()=>fileRef.current?.click()}
          style={{border:"3px dashed #999",padding:20,textAlign:"center",cursor:"pointer",background:"#F9F9F9",minHeight:110,display:"flex",alignItems:"center",justifyContent:"center",marginBottom:8}}>
          {imgPrev
            ? <img src={imgPrev} alt="" style={{maxHeight:180,maxWidth:"100%",objectFit:"contain"}} />
            : <div style={{color:"#aaa"}}><div style={{fontSize:40,marginBottom:6}}>📸</div><div style={{fontSize:13}}>點擊選取截圖</div></div>}
        </div>
        <input ref={fileRef} type="file" accept="image/*" onChange={handleFile} style={{display:"none"}} />
        {imgPrev && (
          <button onClick={()=>{setImgData(null);setImgPrev(null);fileRef.current.value="";}}
            style={{fontSize:12,padding:"3px 12px",border:"2px solid #ccc",background:"#fff",cursor:"pointer",marginBottom:10}}>
            × 移除圖片
          </button>
        )}

        {/* 備註 */}
        <label style={{display:"block",fontWeight:700,fontSize:13,marginBottom:6}}>備註說明（選填）</label>
        <textarea value={note} onChange={e=>setNote(e.target.value)} rows={3}
          placeholder="例如：拜訪了舊同事，深聊3小時..." style={{width:"100%",padding:10,border:"3px solid #ccc",fontSize:14,resize:"vertical",boxSizing:"border-box",fontFamily:"inherit",marginBottom:14}} />

        <button onClick={submit} disabled={busy}
          style={{width:"100%",background:busy?"#ccc":"#1A1A2E",color:"#F8C500",border:"3px solid #F8C500",padding:14,fontFamily:"monospace",fontSize:13,cursor:busy?"not-allowed":"pointer",fontWeight:900,boxShadow:busy?"none":"4px 4px 0 #F8C500"}}>
          {busy?"⏳ 上傳中...":"▶ 提交任務成果"}
        </button>
      </div>
      <div style={{background:"#FFF9E0",border:"3px solid #F8C500",padding:12,fontSize:13}}>
        ⏰ 每週日 23:00 截止。逾時自動計入下一週成績。
      </div>
    </div>
  );
}

// ══════════════════════════════════════════
// HISTORY TAB
// ══════════════════════════════════════════
function HistoryTab({me, users, subs, saveSubs, showToast, sfx}) {
  const [fw, setFw]       = useState("all");
  const [lightbox, setLB] = useState(null);
  const isAdmin = me.isAdmin;
  const mine = isAdmin ? subs : subs.filter(s=>s.userId===me.id);
  const filtered = fw==="all" ? mine : mine.filter(s=>s.week===parseInt(fw));
  const sorted   = [...filtered].sort((a,b)=>new Date(b.ts)-new Date(a.ts));
  const getUser  = id => users.find(u=>u.id===id);
  const getTask  = id => TASKS.find(t=>t.id===id);

  const del = async id => {
    if (!window.confirm("確定刪除？")) return;
    await saveSubs(subs.filter(s=>s.id!==id));
    sfx.error(); showToast("已刪除","err");
  };

  return (
    <div>
      {lightbox && (
        <div onClick={()=>setLB(null)} style={{position:"fixed",inset:0,background:"rgba(0,0,0,.92)",zIndex:9999,display:"flex",alignItems:"center",justifyContent:"center",cursor:"zoom-out"}}>
          <img src={lightbox} alt="" style={{maxWidth:"95vw",maxHeight:"90vh",objectFit:"contain"}} />
        </div>
      )}
      <div style={{display:"flex",gap:6,marginBottom:14,flexWrap:"wrap"}}>
        <button onClick={()=>setFw("all")} style={{padding:"5px 12px",border:"2px solid #000",cursor:"pointer",fontWeight:700,fontSize:12,background:fw==="all"?"#1A1A2E":"#fff",color:fw==="all"?"#F8C500":"#000"}}>全部</button>
        {WEEKS.map(w=>(
          <button key={w.week} onClick={()=>setFw(String(w.week))} style={{padding:"5px 12px",border:"2px solid #000",cursor:"pointer",fontWeight:700,fontSize:12,fontFamily:"monospace",background:fw===String(w.week)?"#1A1A2E":"#fff",color:fw===String(w.week)?"#F8C500":"#000"}}>W{w.week}</button>
        ))}
      </div>
      {sorted.length===0&&<div style={{textAlign:"center",padding:40,color:"#aaa",border:"2px dashed #ccc"}}>尚無記錄</div>}
      {sorted.map(s=>{
        const task=getTask(s.taskId); const user=getUser(s.userId);
        const c = user ? getChar(user.charId||"mario") : CHARACTERS[0];
        return (
          <div key={s.id} style={{background:"#fff",border:"3px solid #000",boxShadow:"3px 3px 0 #000",marginBottom:10,padding:14,display:"flex",gap:12,alignItems:"flex-start"}}>
            {s.imgData&&<img src={s.imgData} alt="" onClick={()=>setLB(s.imgData)} style={{width:68,height:68,objectFit:"cover",border:"2px solid #000",cursor:"zoom-in",flexShrink:0}} />}
            <div style={{flex:1,minWidth:0}}>
              <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:4,flexWrap:"wrap"}}>
                <span style={{fontSize:18}}>{task?.emoji}</span>
                <strong style={{fontSize:14}}>{task?.label}</strong>
                <span style={{fontFamily:"monospace",fontWeight:900,color:"#E52222"}}>+{s.xp}XP</span>
                <span style={{background:"#1A1A2E",color:"#F8C500",fontSize:10,padding:"2px 7px",fontFamily:"monospace"}}>W{s.week}</span>
              </div>
              {isAdmin&&user&&<div style={{fontSize:12,color:"#888",marginBottom:3,display:"flex",alignItems:"center",gap:6}}><CharAvatar charId={user.charId||"mario"} size={24}/> {user.realName||user.name}（{user.name}）</div>}
              {s.note&&<div style={{fontSize:12,color:"#555",lineHeight:1.7,marginBottom:3}}>{s.note}</div>}
              <div style={{fontSize:11,color:"#bbb"}}>{new Date(s.ts).toLocaleString("zh-TW")}</div>
            </div>
            {(isAdmin||s.userId===me.id)&&(
              <button onClick={()=>del(s.id)} style={{border:"2px solid #E52222",color:"#E52222",background:"#fff",padding:"4px 10px",cursor:"pointer",fontSize:12,flexShrink:0}}>刪除</button>
            )}
          </div>
        );
      })}
    </div>
  );
}

