// ══════════════════════════════════════════
// ADMIN TAB
// ══════════════════════════════════════════
function AdminTab({users, saveUsers, subs, saveSubs, weekBonuses, getBonus, saveWeekBonus, showToast, sfx}) {
  const [sub, setSub] = useState("members");
  const [edit, setEdit] = useState(null);
  const [eN,setEN]=useState(""); const [eRN,setERN]=useState(""); const [eT,setET]=useState(""); const [ePw,setEPw]=useState(""); const [eSq,setESq]=useState("");
  const [nN,setNN]=useState(""); const [nT,setNT]=useState("red"); const [nSq,setNSq]=useState(""); const [nPw,setNPw]=useState("1234");
  // RNG Buff states
  const [rngResult, setRngResult] = useState(null);
  const [rngAnim, setRngAnim] = useState(false);
  const [rngSaving, setRngSaving] = useState(false);

  const startEdit = u => { setEdit(u); setEN(u.name); setERN(u.realName||""); setET(u.team); setESq(u.squad||""); setEPw(""); };
  const saveEdit = async () => {
    if (!eN.trim()) { showToast("名稱不能空白","err"); return; }
    const next = users.map(u=>u.id===edit.id?{...u,name:eN.trim(),realName:eRN.trim(),team:eT,squad:eSq.trim(),...(ePw?{password:ePw}:{})}:u);
    await saveUsers(next); sfx.coin(); showToast("已更新"); setEdit(null);
  };
  const resetSetup = async uid => {
    if (!window.confirm("確定重置此成員的設定（需重新設定密碼和角色）？")) return;
    const next = users.map(u=>u.id===uid?{...u,setupDone:false,password:"",charId:"",realName:""}:u);
    await saveUsers(next); sfx.error(); showToast("已重置，該成員下次登入需重新設定","err");
  };
  const addUser = async () => {
    if (!nN.trim()) { showToast("請輸入名稱","err"); return; }
    const id = "u"+Date.now();
    await saveUsers([...users,{id,name:nN.trim(),team:nT,squad:nSq.trim(),password:"",charId:"",setupDone:false,realName:""}]);
    sfx.levelUp(); showToast("新增成功！"); setNN(""); setNPw("1234");
  };
  const delUser = async uid => {
    if (!window.confirm("確定刪除此成員？")) return;
    await saveUsers(users.filter(u=>u.id!==uid)); sfx.error(); showToast("已刪除","err");
  };
  const clearSubs = async () => {
    if (!window.confirm("⚠️ 清空所有記錄？無法復原！")) return;
    await saveSubs([]); sfx.error(); showToast("已清空","err");
  };

  // Backup / Restore
  const backupData = () => {
    const data = { exportTime:new Date().toISOString(), users, subs, weekBonuses };
    const blob = new Blob([JSON.stringify(data,null,2)],{type:"application/json"});
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url; a.download = `mario-backup-${new Date().toISOString().slice(0,10)}.json`;
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
    URL.revokeObjectURL(url); showToast("✅ 備份已下載");
  };
  const restoreData = async (e) => {
    const file = e.target.files[0]; if (!file) return;
    if (!window.confirm("⚠️ 確定還原？這將覆蓋所有現有資料！")) { e.target.value=""; return; }
    try {
      const data = JSON.parse(await file.text());
      if (data.users) await saveUsers(data.users);
      if (data.subs) await saveSubs(data.subs);
      if (data.weekBonuses) for (const [w,b] of Object.entries(data.weekBonuses)) await saveWeekBonus(Number(w),b);
      sfx.levelUp(); showToast("✅ 資料還原成功！");
    } catch(err) { showToast("❌ 檔案格式錯誤","err"); }
    e.target.value="";
  };

  // RNG helpers
  const MULTIPLIERS = [3, 4, 5, 6, 7, 8, 10];
  const doRng = () => {
    setRngAnim(true); setRngResult(null);
    let count = 0;
    const interval = setInterval(() => {
      const t = TASKS[Math.floor(Math.random()*TASKS.length)];
      const m = MULTIPLIERS[Math.floor(Math.random()*MULTIPLIERS.length)];
      setRngResult({ taskId:t.id, multiplier:m, label:`${t.label}每份+${m}分`, taskLabel:t.label, emoji:t.emoji });
      count++;
      if (count >= 18) { clearInterval(interval); setRngAnim(false); }
    }, 80);
  };
  const confirmBonus = async (targetWeek) => {
    if (!rngResult) return;
    setRngSaving(true);
    const bonus = { taskId: rngResult.taskId, multiplier: rngResult.multiplier, label: rngResult.label };
    await saveWeekBonus(targetWeek, bonus);
    sfx.levelUp(); showToast(`✅ W${targetWeek} 加權已設定：${bonus.label}`);
    setRngResult(null); setRngSaving(false);
  };
  const clearBonus = async (targetWeek) => {
    await saveWeekBonus(targetWeek, null);
    sfx.error(); showToast(`W${targetWeek} 加權已清除`, "err");
  };
  const curWeek = (() => {
    const now = new Date();
    for (const w of WEEKS) {
      if (now >= new Date(w.start+"T00:00:00") && now <= new Date(w.end+"T23:00:00")) return w.week;
    }
    return WEEKS.length;
  })();
  const nextWeek = Math.min(curWeek + 1, WEEKS.length);

  const adTabs = [{id:"members",label:"成員管理"},{id:"add",label:"新增成員"},{id:"subs",label:"所有記錄"},{id:"rng",label:"🎲 RNG Buff"},{id:"backup",label:"💾 備份"}];
  return (
    <div>
      <div style={{background:"#E52222",color:"#fff",border:"3px solid #000",padding:"10px 16px",marginBottom:14,fontWeight:900}}>👑 管理者後台 — 謹慎操作</div>
      <div style={{display:"flex",gap:0,border:"2px solid #000",marginBottom:16,overflow:"hidden"}}>
        {adTabs.map(t=>(
          <button key={t.id} onClick={()=>setSub(t.id)} style={{flex:1,padding:"10px 8px",border:"none",borderRight:"2px solid #ccc",cursor:"pointer",fontWeight:700,fontSize:12,fontFamily:"'Noto Sans TC',sans-serif",background:sub===t.id?"#1A1A2E":"#fff",color:sub===t.id?"#F8C500":"#000"}}>{t.label}</button>
        ))}
      </div>

      {sub==="members" && (
        <div>
          {edit && (
            <div style={{background:"#FFF9E0",border:"3px solid #F8C500",padding:16,marginBottom:16,boxShadow:"4px 4px 0 #F8C500"}}>
              <div style={{fontWeight:900,marginBottom:12}}>✏️ 編輯：{edit.name}</div>
              <input value={eN} onChange={e=>setEN(e.target.value)} placeholder="小隊名稱" style={{display:"block",width:"100%",padding:8,border:"2px solid #000",marginBottom:8,fontSize:14,boxSizing:"border-box"}} />
              <input value={eRN} onChange={e=>setERN(e.target.value)} placeholder="真實姓名" style={{display:"block",width:"100%",padding:8,border:"2px solid #000",marginBottom:8,fontSize:14,boxSizing:"border-box"}} />
              <input value={eSq} onChange={e=>setESq(e.target.value)} placeholder="所屬小隊（例：怡方小C）" style={{display:"block",width:"100%",padding:8,border:"2px solid #000",marginBottom:8,fontSize:14,boxSizing:"border-box"}} />
              <select value={eT} onChange={e=>setET(e.target.value)} style={{display:"block",width:"100%",padding:8,border:"2px solid #000",marginBottom:8,fontSize:14}}>
                <option value="red">🔴 瑪利歐紅隊</option>
                <option value="green">🟢 路易吉綠隊</option>
              </select>
              <input value={ePw} onChange={e=>setEPw(e.target.value)} placeholder="新密碼（留空不變）" type="password" style={{display:"block",width:"100%",padding:8,border:"2px solid #000",marginBottom:10,fontSize:14,boxSizing:"border-box"}} />
              <div style={{display:"flex",gap:8}}>
                <button onClick={saveEdit} style={{flex:1,background:"#1A1A2E",color:"#F8C500",border:"2px solid #F8C500",padding:10,cursor:"pointer",fontWeight:900}}>儲存</button>
                <button onClick={()=>setEdit(null)} style={{padding:"10px 20px",border:"2px solid #ccc",background:"#fff",cursor:"pointer"}}>取消</button>
              </div>
            </div>
          )}
          {["red","green"].map(team=>{
            const squads = [...new Set(users.filter(u=>u.team===team).map(u=>u.squad||"（未分配小隊）"))].sort();
            return (
              <div key={team} style={{marginBottom:16}}>
                <div style={{fontWeight:900,fontSize:14,marginBottom:8,color:team==="red"?"#E52222":"#2DAD3F"}}>{team==="red"?"🔴 瑪利歐紅隊":"🟢 路易吉綠隊"} ({users.filter(u=>u.team===team).length}人)</div>
                {squads.map(sq=>(
                  <div key={sq} style={{marginBottom:12}}>
                    <div style={{fontSize:12,fontWeight:700,color:"#555",background:"#f5f5f5",padding:"4px 10px",border:"1px solid #ddd",marginBottom:6}}>🏷️ {sq}</div>
                    {users.filter(u=>u.team===team&&(u.squad||"（未分配小隊）")===sq).map(u=>{
                      const c = getChar(u.charId||"mario");
                      return (
                        <div key={u.id} style={{display:"flex",alignItems:"center",gap:8,border:"2px solid #ddd",padding:"9px 12px",marginBottom:4,background:"#fff",flexWrap:"wrap"}}>
                          <span>{u.setupDone?<CharAvatar charId={u.charId||"mario"} size={34}/>:<span style={{fontSize:20}}>❓</span>}</span>
                          <div style={{flex:1}}>
                            <div style={{fontWeight:700,fontSize:13}}>{u.name}{u.realName?<span style={{color:"#888",fontWeight:400}}> ({u.realName})</span>:""}</div>
                            <div style={{fontSize:10,color:"#aaa"}}>{u.setupDone?"✅ 已設定":"⏳ 尚未設定"}</div>
                          </div>
                          <button onClick={()=>startEdit(u)} style={{padding:"4px 10px",border:"2px solid #1565C0",color:"#1565C0",background:"#fff",cursor:"pointer",fontSize:12,fontWeight:700}}>編輯</button>
                          <button onClick={()=>resetSetup(u.id)} style={{padding:"4px 10px",border:"2px solid #E07800",color:"#E07800",background:"#fff",cursor:"pointer",fontSize:12}}>重置</button>
                          <button onClick={()=>delUser(u.id)} style={{padding:"4px 8px",border:"2px solid #E52222",color:"#E52222",background:"#fff",cursor:"pointer",fontSize:12}}>✕</button>
                        </div>
                      );
                    })}
                  </div>
                ))}
              </div>
            );
          })}
        </div>
      )}

      {sub==="add" && (
        <div style={{background:"#fff",border:"3px solid #000",padding:20,boxShadow:"4px 4px 0 #000"}}>
          <div style={{fontWeight:900,fontSize:15,marginBottom:14}}>➕ 新增成員</div>
          <input value={nN} onChange={e=>setNN(e.target.value)} placeholder="個人登入名稱（例：怡方、小C）" style={{display:"block",width:"100%",padding:10,border:"3px solid #000",marginBottom:10,fontSize:15,boxSizing:"border-box"}} />
          <input value={nSq} onChange={e=>setNSq(e.target.value)} placeholder="所屬小隊（例：怡方小C）" style={{display:"block",width:"100%",padding:10,border:"3px solid #000",marginBottom:10,fontSize:15,boxSizing:"border-box"}} />
          <select value={nT} onChange={e=>setNT(e.target.value)} style={{display:"block",width:"100%",padding:10,border:"3px solid #000",marginBottom:14,fontSize:15}}>
            <option value="red">🔴 瑪利歐紅隊</option>
            <option value="green">🟢 路易吉綠隊</option>
          </select>
          <p style={{fontSize:12,color:"#888",marginBottom:12}}>✅ 新成員首次登入時，系統會引導他設定真實姓名、角色和密碼。</p>
          <button onClick={addUser} style={{width:"100%",background:"#2DAD3F",color:"#fff",border:"3px solid #000",padding:12,cursor:"pointer",fontWeight:900,fontSize:14,boxShadow:"3px 3px 0 #000"}}>➕ 新增成員</button>
        </div>
      )}

      {sub==="subs" && (
        <div>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}>
            <div style={{fontWeight:700}}>共 {subs.length} 筆記錄</div>
            <button onClick={clearSubs} style={{padding:"6px 14px",background:"#E52222",color:"#fff",border:"2px solid #000",cursor:"pointer",fontWeight:700,fontSize:12}}>⚠️ 清空全部</button>
          </div>
          <HistoryTab me={ADMIN_ACCOUNT} users={users} subs={subs} saveSubs={saveSubs} showToast={showToast} sfx={{error:()=>{}}} />
        </div>
      )}

      {sub==="rng" && (
        <div>
          <div style={{background:"#fff",border:"3px solid #000",padding:16,boxShadow:"4px 4px 0 #000",marginBottom:16}}>
            <div style={{fontWeight:900,fontSize:15,marginBottom:14}}>🎲 RNG Buff 隨機加權系統</div>
            <div style={{fontSize:12,color:"#888",marginBottom:16}}>每週隨機抽選一個任務項目作為當週加分項目。按下「擲骰」後選擇要套用的週次。</div>

            <div style={{marginBottom:16}}>
              <div style={{fontWeight:700,fontSize:13,marginBottom:8}}>📅 各週加權狀態</div>
              {WEEKS.map(w => {
                const b = getBonus(w.week);
                const task = b ? TASKS.find(t=>t.id===b.taskId) : null;
                return (
                  <div key={w.week} style={{display:"flex",alignItems:"center",gap:8,padding:"8px 10px",border:"2px solid #ddd",marginBottom:6,background: b ? "#FFF9E0" : "#f9f9f9"}}>
                    <div style={{fontWeight:700,minWidth:30,fontSize:13}}>W{w.week}</div>
                    <div style={{flex:1,fontSize:12}}>
                      {b ? (
                        <span style={{color:"#E07800",fontWeight:700}}>{task?.emoji} {b.label}</span>
                      ) : (
                        <span style={{color:"#aaa"}}>（無加權）</span>
                      )}
                    </div>
                    {b && (
                      <button onClick={()=>clearBonus(w.week)} style={{padding:"3px 8px",border:"2px solid #E52222",color:"#E52222",background:"#fff",cursor:"pointer",fontSize:11,fontWeight:700}}>清除</button>
                    )}
                  </div>
                );
              })}
            </div>

            <div style={{textAlign:"center",marginBottom:16}}>
              <button onClick={doRng} disabled={rngAnim} style={{padding:"14px 40px",background: rngAnim ? "#999" : "#1A1A2E",color:"#F8C500",border:"3px solid #000",cursor: rngAnim ? "not-allowed" : "pointer",fontWeight:900,fontSize:18,boxShadow:"4px 4px 0 #000",letterSpacing:2}}>
                {rngAnim ? "🎰 擲骰中…" : "🎲 擲骰！"}
              </button>
            </div>

            {rngResult && (
              <div style={{background: rngAnim ? "#1A1A2E" : "#FFF9E0",border:"3px solid #F8C500",padding:16,boxShadow:"4px 4px 0 #F8C500",marginBottom:16,textAlign:"center"}}>
                <div style={{fontSize:28,marginBottom:4}}>{rngResult.emoji}</div>
                <div style={{fontWeight:900,fontSize:20,color: rngAnim ? "#F8C500" : "#E07800",marginBottom:4}}>{rngResult.taskLabel}</div>
                <div style={{fontSize:15,fontWeight:700,marginBottom: rngAnim ? 0 : 14}}>每份 +{rngResult.multiplier} 分</div>
                {!rngAnim && (
                  <div>
                    <div style={{fontSize:12,color:"#888",marginBottom:10}}>套用到哪一週？</div>
                    <div style={{display:"flex",gap:8,justifyContent:"center",flexWrap:"wrap"}}>
                      {WEEKS.map(w => (
                        <button key={w.week} onClick={()=>confirmBonus(w.week)} disabled={rngSaving} style={{padding:"8px 14px",background:"#2DAD3F",color:"#fff",border:"3px solid #000",cursor: rngSaving ? "not-allowed" : "pointer",fontWeight:900,fontSize:13,boxShadow:"3px 3px 0 #000"}}>
                          W{w.week}
                        </button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      )}

      {sub==="backup" && (
        <div>
          <div style={{background:"#fff",border:"3px solid #000",padding:20,marginBottom:16,boxShadow:"4px 4px 0 #000"}}>
            <div style={{fontWeight:900,fontSize:15,marginBottom:8}}>💾 資料備份</div>
            <div style={{fontSize:12,color:"#888",marginBottom:16}}>將目前所有資料（成員、記錄、加權設定）匯出為 JSON 檔案。</div>
            <button onClick={backupData} style={{width:"100%",background:"#1A1A2E",color:"#F8C500",border:"3px solid #000",padding:12,cursor:"pointer",fontWeight:900,fontSize:14,boxShadow:"3px 3px 0 #000",marginBottom:20}}>⬇️ 下載備份 JSON</button>
            <div style={{fontWeight:900,fontSize:15,marginBottom:8}}>📥 還原資料</div>
            <div style={{fontSize:12,color:"#E52222",marginBottom:12}}>⚠️ 上傳備份檔案將覆蓋所有現有資料，請謹慎操作！</div>
            <input type="file" accept=".json" onChange={restoreData} style={{display:"block",width:"100%",padding:10,border:"3px solid #E52222",boxSizing:"border-box",fontSize:13}} />
          </div>
        </div>
      )}
    </div>
  );
}

// ══════════════════════════════════════════
// 共用元件
// ══════════════════════════════════════════
function Card({title, children}) {
  return (
    <div style={{background:"#fff",border:"3px solid #000",boxShadow:"5px 5px 0 #000",marginBottom:16,overflow:"hidden"}}>
      <div style={{background:"#1A1A2E",color:"#F8C500",padding:"10px 16px",fontWeight:900,fontSize:15}}>{title}</div>
      <div style={{padding:16}}>{children}</div>
    </div>
  );
}

function Toast({msg, type}) {
  const bg = type==="err" ? "#E52222" : "#2DAD3F";
  return (
    <div style={{position:"fixed",top:76,left:"50%",transform:"translateX(-50%)",background:bg,color:"#fff",padding:"12px 24px",border:"3px solid #000",boxShadow:"4px 4px 0 #000",zIndex:99999,fontWeight:900,fontSize:14,whiteSpace:"nowrap",animation:"tin .3s ease",pointerEvents:"none"}}>
      {msg}
      <style>{`@keyframes tin{from{opacity:0;transform:translateX(-50%) translateY(-14px)}to{opacity:1;transform:translateX(-50%) translateY(0)}}`}</style>
    </div>
  );
}

// ══════════════════════════════════════════
// MONITOR BOARD
// ══════════════════════════════════════════
function MonitorBoard({users, subs, curWeek}) {
  const weeks = [1,2,3,4,5,6];
  // Weekly XP per team
  const teamWeekXP = {red:{}, green:{}};
  weeks.forEach(w => { teamWeekXP.red[w]=0; teamWeekXP.green[w]=0; });
  subs.forEach(s => {
    const u = users.find(x=>x.id===s.userId);
    if (u && teamWeekXP[u.team]) teamWeekXP[u.team][s.week] = (teamWeekXP[u.team][s.week]||0) + s.xp;
  });
  // Per-user total XP
  const userXP = {};
  users.forEach(u=>{ userXP[u.id]=0; });
  subs.forEach(s=>{ userXP[s.userId]=(userXP[s.userId]||0)+s.xp; });
  // Team stats
  const redMembers = users.filter(u=>u.team==="red"&&u.setupDone);
  const greenMembers = users.filter(u=>u.team==="green"&&u.setupDone);
  const redTotal = Object.values(teamWeekXP.red).reduce((a,b)=>a+b,0);
  const greenTotal = Object.values(teamWeekXP.green).reduce((a,b)=>a+b,0);
  const redAvg = redMembers.length ? (redTotal/redMembers.length).toFixed(1) : "0.0";
  const greenAvg = greenMembers.length ? (greenTotal/greenMembers.length).toFixed(1) : "0.0";
  // Task breakdown
  const taskCounts = {};
  subs.forEach(s=>{ taskCounts[s.taskId]=(taskCounts[s.taskId]||0)+1; });
  const maxTaskCnt = Math.max(...TASKS.map(t=>taskCounts[t.id]||0), 1);
  // Chart
  const chartW = 280, chartH = 110;
  const barW = 16;
  const gap = Math.floor((chartW - weeks.length*(barW*2+4)) / (weeks.length+1));
  const maxXP = Math.max(...weeks.map(w=>Math.max(teamWeekXP.red[w]||0, teamWeekXP.green[w]||0)), 1);

  return (
    <div style={{paddingBottom:20}}>
      <div style={{background:"#1A1A2E",color:"#F8C500",border:"3px solid #F8C500",padding:"12px 16px",marginBottom:16,boxShadow:"5px 5px 0 #F8C500"}}>
        <div style={{fontFamily:"monospace",fontSize:11,marginBottom:2}}>📊 MONITOR BOARD</div>
        <div style={{fontWeight:900,fontSize:15}}>戰力分析儀表板</div>
      </div>

      {/* Battle Power Cards */}
      <div style={{display:"flex",gap:12,marginBottom:16}}>
        <div style={{flex:1,background:"#FFECEC",border:"3px solid #E52222",padding:14,textAlign:"center",boxShadow:"3px 3px 0 #E52222"}}>
          <div style={{fontSize:11,color:"#E52222",fontWeight:700,marginBottom:4}}>🔴 紅隊 人均戰力</div>
          <div style={{fontSize:30,fontWeight:900,color:"#E52222",lineHeight:1}}>{redAvg}</div>
          <div style={{fontSize:10,color:"#aaa",marginTop:4}}>XP / 人（{redMembers.length}人）</div>
        </div>
        <div style={{flex:1,background:"#EFFFEC",border:"3px solid #2DAD3F",padding:14,textAlign:"center",boxShadow:"3px 3px 0 #2DAD3F"}}>
          <div style={{fontSize:11,color:"#2DAD3F",fontWeight:700,marginBottom:4}}>🟢 綠隊 人均戰力</div>
          <div style={{fontSize:30,fontWeight:900,color:"#2DAD3F",lineHeight:1}}>{greenAvg}</div>
          <div style={{fontSize:10,color:"#aaa",marginTop:4}}>XP / 人（{greenMembers.length}人）</div>
        </div>
      </div>

      {/* Weekly XP Chart */}
      <div style={{background:"#fff",border:"3px solid #000",padding:14,marginBottom:16,boxShadow:"4px 4px 0 #000"}}>
        <div style={{fontWeight:900,fontSize:13,marginBottom:10}}>📈 週次 XP 趨勢（隊伍）</div>
        <svg width="100%" viewBox={`0 0 ${chartW+50} ${chartH+35}`}>
          {/* Y axis */}
          <line x1={38} y1={0} x2={38} y2={chartH} stroke="#ccc" strokeWidth={1}/>
          {/* X axis */}
          <line x1={38} y1={chartH} x2={chartW+42} y2={chartH} stroke="#000" strokeWidth={2}/>
          {weeks.map((w,wi) => {
            const rH = Math.max(((teamWeekXP.red[w]||0)/maxXP)*chartH, 0);
            const gH = Math.max(((teamWeekXP.green[w]||0)/maxXP)*chartH, 0);
            const x = 42 + wi*(barW*2+gap+2);
            return (
              <g key={w}>
                <rect x={x} y={chartH-rH} width={barW} height={rH} fill="#E52222" rx={2}/>
                <text x={x+barW/2} y={chartH-rH-3} textAnchor="middle" fontSize={8} fill="#E52222" fontWeight="bold">
                  {teamWeekXP.red[w]||""}
                </text>
                <rect x={x+barW+2} y={chartH-gH} width={barW} height={gH} fill="#2DAD3F" rx={2}/>
                <text x={x+barW+2+barW/2} y={chartH-gH-3} textAnchor="middle" fontSize={8} fill="#2DAD3F" fontWeight="bold">
                  {teamWeekXP.green[w]||""}
                </text>
                <text x={x+barW+1} y={chartH+12} textAnchor="middle" fontSize={9} fill={w===curWeek?"#E07800":"#666"} fontWeight={w===curWeek?"bold":"normal"}>
                  W{w}
                </text>
              </g>
            );
          })}
        </svg>
        <div style={{display:"flex",gap:16,fontSize:11,marginTop:4}}>
          <span><span style={{color:"#E52222"}}>■</span> 紅隊</span>
          <span><span style={{color:"#2DAD3F"}}>■</span> 綠隊</span>
        </div>
      </div>

      {/* Individual Ranking */}
      <div style={{background:"#fff",border:"3px solid #000",padding:14,marginBottom:16,boxShadow:"4px 4px 0 #000"}}>
        <div style={{fontWeight:900,fontSize:13,marginBottom:12}}>🏆 個人戰力排名</div>
        {[...users].filter(u=>u.setupDone).sort((a,b)=>(userXP[b.id]||0)-(userXP[a.id]||0)).map((u,i) => {
          const xp = userXP[u.id]||0;
          const maxXpU = Math.max(...users.filter(x=>x.setupDone).map(x=>userXP[x.id]||0), 1);
          const pct = Math.max((xp/maxXpU)*100, 0);
          const medals = ["🥇","🥈","🥉"];
          const isRed = u.team==="red";
          return (
            <div key={u.id} style={{marginBottom:10}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",fontSize:12,marginBottom:4}}>
                <span style={{fontWeight:700}}>{medals[i]||`#${i+1}`} {u.name}{u.realName?` (${u.realName})`:""}</span>
                <span style={{fontWeight:900,color:isRed?"#E52222":"#2DAD3F"}}>{xp} XP</span>
              </div>
              <div style={{height:10,background:"#f0f0f0",border:"1px solid #ddd",borderRadius:2,overflow:"hidden"}}>
                <div style={{height:"100%",width:`${pct}%`,background:isRed?"#E52222":"#2DAD3F",transition:"width .3s"}}/>
              </div>
            </div>
          );
        })}
        {users.filter(u=>!u.setupDone).length > 0 && (
          <div style={{fontSize:11,color:"#aaa",marginTop:8}}>⏳ 尚有 {users.filter(u=>!u.setupDone).length} 人未完成設定</div>
        )}
      </div>

      {/* Task Distribution */}
      <div style={{background:"#fff",border:"3px solid #000",padding:14,boxShadow:"4px 4px 0 #000"}}>
        <div style={{fontWeight:900,fontSize:13,marginBottom:12}}>📊 任務提交分佈（全期）</div>
        {TASKS.map(t => {
          const cnt = taskCounts[t.id]||0;
          const pct = Math.max((cnt/maxTaskCnt)*100, 0);
          const totalSubs = subs.length;
          const ratioTxt = totalSubs ? `${((cnt/totalSubs)*100).toFixed(0)}%` : "0%";
          return (
            <div key={t.id} style={{marginBottom:10}}>
              <div style={{display:"flex",justifyContent:"space-between",fontSize:12,marginBottom:4}}>
                <span>{t.emoji} {t.label}</span>
                <span style={{fontWeight:700}}>{cnt} 筆 <span style={{fontWeight:400,color:"#888"}}>({ratioTxt})</span></span>
              </div>
              <div style={{height:10,background:"#f0f0f0",border:"1px solid #ddd",borderRadius:2,overflow:"hidden"}}>
                <div style={{height:"100%",width:`${pct}%`,background:t.color,transition:"width .3s"}}/>
              </div>
            </div>
          );
        })}
        <div style={{fontSize:11,color:"#888",marginTop:8,textAlign:"right"}}>共 {subs.length} 筆提交記錄</div>
      </div>
    </div>
  );
}
